import{_ as t,c as e,o as r,a5 as d}from"./chunks/framework.DwbewbAn.js";const _=JSON.parse('{"title":"比较判断","description":"","frontmatter":{},"headers":[],"relativePath":"doc/编程语言/后端/Shell/实战/比较.md","filePath":"packages/doc/src/编程语言/后端/Shell/实战/比较.md","lastUpdated":1711551906000}'),l={name:"doc/编程语言/后端/Shell/实战/比较.md"},a=d('<h1 id="比较判断" tabindex="-1">比较判断 <a class="header-anchor" href="#比较判断" aria-label="Permalink to &quot;比较判断&quot;">​</a></h1><ul><li><a href="https://blog.csdn.net/jetliu05/article/details/120648973" target="_blank" rel="noreferrer">参考</a></li></ul><h2 id="字符串比较" tabindex="-1">字符串比较 <a class="header-anchor" href="#字符串比较" aria-label="Permalink to &quot;字符串比较&quot;">​</a></h2><table><thead><tr><th>Bourne Shell</th><th>Korn Shell</th><th>说明</th></tr></thead><tbody><tr><td>[ str1 = str2 ]</td><td>[[ str1 == str2 ]]</td><td>判断字符串str1是否等于str2</td></tr><tr><td>[ str1 != str2 ]</td><td>[[ str1 != str2 ]]</td><td>判断字符串str1是否不等于str2</td></tr><tr><td>NA</td><td>[[ str1 == pattern ]]</td><td>判断字符串str1是否匹配pattern</td></tr><tr><td>NA</td><td>[[ str1 != pattern ]]</td><td>判断字符串str1是否不匹配pattern</td></tr><tr><td>[ str1 &lt; str2 ]</td><td>[[ str1 &lt; str2 ]]</td><td>判断字符串str1按字典顺序是否小于str2</td></tr><tr><td>[ str1 &gt; str2 ]</td><td>[[ str1 &gt; str2 ]]</td><td>判断字符串str1按字典顺序是否大于str2</td></tr><tr><td>[ -z str1 ]</td><td>[[ -z str1 ]]</td><td>判断字符串str1是否为空，注意在变量前后要加双引号</td></tr><tr><td>[ -n str1 ]</td><td>[[ -n str1 ]]</td><td>判断字符串str1是否不为空，注意在变量前后要加双引号</td></tr></tbody></table><h2 id="判断文件权限" tabindex="-1">判断文件权限 <a class="header-anchor" href="#判断文件权限" aria-label="Permalink to &quot;判断文件权限&quot;">​</a></h2><p>| 标记 | Bourne Shell | Korn Shell | 说明 | |---|---|---| | -r | [-r file ] | [[ -r fille ]] | 判断用户对文件是否有可读权限 | | -w | [ -w file] | [[ -w file ]] | 判断用户对文件是否有可写权限 | | -x | [ -x file ] | [[ -x file ]] | 判断用户对文件是否有可执行权限 | | -O | [ -O file ] | [[ -O file ]] | 判断用户是否是文件的属主 | | -G | [ -G file ] | [[ -G file ]] | 判断文件的属组是否和用户的属组相同 | | -u | [ -u file ] | [[- u file ]] | 判断文件是否设置了set-user-ID | | -g | [ -g file ] | [[ -g file ]] | 判断文件是否设置了set-group-ID | | -k | [ -k file ] | [[ -k file ]] | 判断文件是否设置了sticky bit |</p><h2 id="判断文件类型" tabindex="-1">判断文件类型 <a class="header-anchor" href="#判断文件类型" aria-label="Permalink to &quot;判断文件类型&quot;">​</a></h2><p>| 标记 | Bourne Shell | Korn Shell | 说明 | |---|---|---| | -f | [-f file ] | [[ -f fille ]] | 判断是否为普通文件 | | -d | [ -d file ] | [[ -d file ]] | 判断是否为目录 | | -c | [ -c file ] | [[ -c file ]] | 判断是否为raw设备 | | -b | [ -b file ] | [[ -b file ]] | 判断是否为块设备 | | -p | [ -p file ] | [[ -p file ]] | 判断是否为管道 | | -S | [ -S file ] | [[ -S file ]] | 判断是否为socket | | -L | [ -L file ] | [[ -L file ]] | 判断是否为符号链接 | | -e | [ -e file ] | [[ -e file ]] | 判断文件是否为存在 | | -s | [ -s file ] | [[ -s file ]] | 判断文件是否为存在且大小大于0 |</p><h2 id="数字比较" tabindex="-1">数字比较 <a class="header-anchor" href="#数字比较" aria-label="Permalink to &quot;数字比较&quot;">​</a></h2><table><thead><tr><th>Bourne Shell</th><th>Korn Shell</th><th>说明</th></tr></thead><tbody><tr><td>[ num1 -eq num2 ]</td><td>((num1 == num2))</td><td>判断数字num1和num2是否相等</td></tr><tr><td>[ num1 -ne num2 ]</td><td>((num1 != num2))</td><td>判断数字num1和num2是否不相等</td></tr><tr><td>[ num1 -lt num2 ]</td><td>((num1 &lt; num2))</td><td>判断数字num1是否小于num2</td></tr><tr><td>[ num1 -gt num2 ]</td><td>((num1 &gt; num2))</td><td>判断数字num1是否大于num2</td></tr><tr><td>[ num1 -le num2 ]</td><td>((num1 &lt;= num2))</td><td>判断数字num1是否小于或等于num2</td></tr><tr><td>[ num1 -ge num2 ]</td><td>((num1 &gt; =num2))</td><td>判断数字num1是否大于或等于num2</td></tr></tbody></table>',10),n=[a];function s(i,u,o,h,f,m){return r(),e("div",null,n)}const p=t(l,[["render",s]]);export{_ as __pageData,p as default};
